#!/bin/bash
# Generated by OrchestKit M134 — issue #1696 (W1e)
#
# Integration test for Step 3 of claude-release-watch.yml — the issue-filing
# loop, extracted to scripts/cc-file-adoption-issues.sh for isolation.
#
# Mocks `gh` via PATH-shadow so cases run with no GitHub API access.
# Each case sets up gaps.json + gh-issue-args.json, invokes the script,
# and asserts on the recorded MOCK_LOG (one line per gh subcommand).
#
# Regression guard for M134: empty `features: []` must produce zero
# `gh issue create` calls and exit 0 (was previously asserted nowhere).

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

# Count occurrences of a literal start-of-line in MOCK_LOG. Returns 0
# when file is missing/empty (a legitimate "no calls" outcome). silent: known-noise
count_calls() {
  local pattern="$1"
  if [ ! -s "$MOCK_LOG" ]; then echo 0; return; fi
  # grep -c exits 1 when no matches — accept that and emit 0. silent: known-noise
  local n
  n=$(grep -cF "${pattern}" "$MOCK_LOG" 2>/dev/null) || n=0  # silent: known-noise
  echo "$n"
}

echo "CC Release Watch — Step 3 issue-filing tests (M134 #1696)"
echo "========================================================="

cd "$PROJECT_ROOT"

# ---- mock gh (PATH-shadow) ----------------------------------------------------
MOCK_DIR=$(mktemp -d)
MOCK_LOG="$MOCK_DIR/gh.log"
export MOCK_LOG
cat > "$MOCK_DIR/gh" <<'MOCK'
#!/usr/bin/env bash
# Minimal gh mock for Step 3. Records every invocation, returns
# deterministic stubs for `api .../milestones`, `issue list`, and
# `issue create`. MOCK_EXISTING_KEYS=k1,k2 makes `issue list` return
# length=1 (existing) for those keys.
set -euo pipefail
# Single-line record per call so grep works even when BODY has newlines.
# %q would shell-quote each arg; we use a custom delimiter for human-readable
# greps in the test asserts (e.g. grep -F -- '|--label cc-adoption,automation|').
{
  printf '%s' "$1"
  for arg in "${@:2}"; do printf '|%s' "${arg//$'\n'/\\n}"; done
  printf '\n'
} >> "$MOCK_LOG"
case "$1" in
  api)
    if [[ "$*" == *"/milestones"* && "$*" != *"-X POST"* ]]; then
      if [ "${MOCK_EXISTING_MILESTONE:-0}" = "1" ]; then echo "42"; fi
      exit 0
    fi
    if [[ "$*" == *"-X POST"* && "$*" == *"/milestones"* ]]; then
      echo "99"
      exit 0
    fi
    ;;
  issue)
    case "$2" in
      list)
        SEARCH=""
        for ((i=1; i<=$#; i++)); do
          if [ "${!i}" = "--search" ]; then
            j=$((i+1)); SEARCH="${!j}"; break
          fi
        done
        # The script passes --search '"Key: \`<KEY>\`" in:body'; extract <KEY>.
        # macOS sed has flaky support for \\\?, so use grep -oE with a char class
        # that explicitly excludes both backtick and backslash.
        KEY=$(echo "$SEARCH" | grep -oE '`[^`\\]+' | head -1 | tr -d '`')
        EXISTING="${MOCK_EXISTING_KEYS:-}"
        if [ -n "$KEY" ] && [ -n "$EXISTING" ] \
           && echo ",$EXISTING," | grep -qF ",$KEY,"; then
          echo "1"
        else
          echo "0"
        fi
        exit 0
        ;;
      create)
        exit 0
        ;;
    esac
    ;;
esac
echo "MOCK_GH: unhandled: $*" >&2
exit 1
MOCK
chmod +x "$MOCK_DIR/gh"
export PATH="$MOCK_DIR:$PATH"

WORK=$(mktemp -d)
cleanup() { rm -rf "$MOCK_DIR" "$WORK"; }
trap cleanup EXIT

if ! command -v gh >/dev/null 2>&1 || [ "$(command -v gh)" != "$MOCK_DIR/gh" ]; then
  echo "FATAL: mock gh not on PATH (got $(command -v gh || echo none))"
  exit 1
fi

mkdir -p "$WORK/shared"

# Legacy cases (1-11) predate the M169 evidence gate and assert pure
# score/dedup/stamp behaviour, so run them with the gate OFF (ORK_EVIDENCE_GATE=0
# = filer's legacy path: file every >=floor feature, recall lane skipped). The
# M169 cases (12+) set ORK_EVIDENCE_GATE=1 + EVIDENCE_ROOTS explicitly per-run.
export ORK_EVIDENCE_GATE=0

# Helper: run script in $WORK against fixture, count `issue create` calls.
run_case() {
  local name="$1" expected="$2" gaps_json="$3" existing="${4:-}"
  : > "$MOCK_LOG"
  echo "$gaps_json" > "$WORK/shared/cc-adoption-gaps.json"
  echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"

  pushd "$WORK" >/dev/null
  local exit_code=0
  MOCK_EXISTING_KEYS="$existing" \
  MOCK_EXISTING_MILESTONE=1 \
  GH_REPO="acme/orchestkit" \
    bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" >"/tmp/step3-$name.out" 2>&1 \
    || exit_code=$?
  popd >/dev/null

  if [ "$exit_code" != "0" ]; then
    log_fail "$name: script exit" "expected 0, got $exit_code (see /tmp/step3-$name.out)"
    return
  fi
  local actual
  actual=$(count_calls "issue|create")
  if [ "$actual" = "$expected" ]; then
    log_pass "$name: $expected issue create call(s)"
  else
    log_fail "$name" "expected $expected create calls, got $actual (see /tmp/step3-$name.out)"
  fi
}

# Sample feature factory.
feat() {
  local slug="$1" score="$2" extra="${3:-{\}}"
  jq -nc --arg s "$slug" --argjson g "$score" --argjson x "$extra" \
    '{feature_slug: $s, gap_score: $g, description: "desc", category: "tooling",
      reference_changelog_line: "- foo", affected_skills: ["s1","s2"]} * $x'
}

# ============================================================================
# Case 1: empty array → 0 creates + graceful "No gaps to triage" message
# ============================================================================
: > "$MOCK_LOG"
echo "[]" > "$WORK/shared/cc-adoption-gaps.json"
echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"
pushd "$WORK" >/dev/null
EXIT=0
GH_REPO="acme/orchestkit" bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" \
  > /tmp/step3-empty.out 2>&1 || EXIT=$?
popd >/dev/null
CALLS=$(count_calls "issue|create")
if [ "$EXIT" = "0" ] && [ "$CALLS" = "0" ] && grep -qF "No gaps to triage" /tmp/step3-empty.out; then
  log_pass "case 1: empty gaps array → 0 creates + clean exit"
else
  log_fail "case 1" "exit=$EXIT, calls=$CALLS, log=$(cat /tmp/step3-empty.out)"
fi

# ============================================================================
# Case 2: REGRESSION GUARD — features: [] must produce 0 creates.
# ============================================================================
GAPS=$(jq -nc '[{version: "2.1.999", features: []}]')
run_case "case2-empty-features" 0 "$GAPS"

# ============================================================================
# Case 3: gap_score < 10 is filtered out
# ============================================================================
LOW=$(feat "low-thing" 5)
GAPS=$(jq -nc --argjson f "$LOW" '[{version: "2.1.999", features: [$f]}]')
run_case "case3-below-floor" 0 "$GAPS"

# ============================================================================
# Case 4: happy path — gap_score == 10 → 1 issue
# ============================================================================
HIT=$(feat "new-feature" 10)
GAPS=$(jq -nc --argjson f "$HIT" '[{version: "2.1.999", features: [$f]}]')
run_case "case4-floor-edge" 1 "$GAPS"

CREATE_LINE=$(grep -F 'issue|create' "$MOCK_LOG" | head -1)
if echo "$CREATE_LINE" | grep -qF -- "|--title|adopt CC 2.1.999 feature: new-feature (tooling)|"; then
  log_pass "case 4: title format = 'adopt CC <ver> feature: <slug> (<cat>)'"
else
  log_fail "case 4: title format" "got: $CREATE_LINE"
fi
if echo "$CREATE_LINE" | grep -qF -- "|--label|cc-adoption,automation|"; then
  log_pass "case 4: label flag = cc-adoption,automation"
else
  log_fail "case 4: label" "labels missing or wrong"
fi
if echo "$CREATE_LINE" | grep -qF -- "|--milestone|CC 2.1.999 adoption"; then
  log_pass "case 4: milestone passed through"
else
  log_fail "case 4: milestone" "milestone not propagated"
fi

# ============================================================================
# Case 5: dedup — an issue with the same Changelog-Ref already exists → 0 creates.
# #2041: the dedup key is now sha256(reference_changelog_line), NOT slug+version,
# so the "existing" marker the mock matches is the hash of the feature's ref line.
# ============================================================================
HIT=$(feat "already-filed" 15)   # reference_changelog_line defaults to "- foo"
GAPS=$(jq -nc --argjson f "$HIT" '[{version: "2.1.999", features: [$f]}]')
# Mirror the filer's normalize_ref ∘ sha256_hex: strip the leading "- " bullet,
# collapse whitespace, then hash (so "- foo" → hash of "foo").
REF_HASH=$(printf '%s' '- foo' \
  | sed -E 's/^[[:space:]]*[-*+][[:space:]]+//; s/[[:space:]]+/ /g; s/^[[:space:]]+//; s/[[:space:]]+$//' \
  | { if command -v sha256sum >/dev/null 2>&1; then sha256sum; else shasum -a 256; fi; } | cut -d' ' -f1)
run_case "case5-dedup" 0 "$GAPS" "$REF_HASH"

if grep -qF 'issue|list' "$MOCK_LOG"; then
  log_pass "case 5: dedup probe (issue list) was invoked"
else
  log_fail "case 5: dedup probe" "issue list never called"
fi

# ============================================================================
# Case 6: mixed scores — only those >= 10 are filed
# ============================================================================
F1=$(feat "low-a" 3)
F2=$(feat "edge-b" 10)
F3=$(feat "high-c" 25)
GAPS=$(jq -nc --argjson a "$F1" --argjson b "$F2" --argjson c "$F3" \
  '[{version: "2.1.999", features: [$a, $b, $c]}]')
run_case "case6-mixed-scores" 2 "$GAPS"

if grep -F 'issue|create' "$MOCK_LOG" | grep -qF "edge-b" \
   && grep -F 'issue|create' "$MOCK_LOG" | grep -qF "high-c" \
   && ! grep -F 'issue|create' "$MOCK_LOG" | grep -qF "low-a"; then
  log_pass "case 6: filtered slugs precisely (edge-b + high-c, NOT low-a)"
else
  log_fail "case 6: slug filter" "wrong slugs filed"
fi

# ============================================================================
# Case 7: two versions, mixed → issues for each version's qualifying features
# ============================================================================
A=$(feat "alpha" 12)
B=$(feat "beta" 18)
GAPS=$(jq -nc --argjson a "$A" --argjson b "$B" \
  '[{version: "2.1.998", features: [$a]}, {version: "2.1.999", features: [$b]}]')
run_case "case7-multi-version" 2 "$GAPS"

if grep -F 'issue|create' "$MOCK_LOG" | grep -qF "CC 2.1.998 feature: alpha" \
   && grep -F 'issue|create' "$MOCK_LOG" | grep -qF "CC 2.1.999 feature: beta"; then
  log_pass "case 7: per-version slug routing (alpha→998, beta→999)"
else
  log_fail "case 7: version routing" "version-slug pairing wrong"
fi

# ============================================================================
# Case 8: feature with below_floor: true (W1h forward-compat) — empty features path
# ============================================================================
GAPS=$(jq -nc '[{version: "2.1.999", features: [], below_floor: true, skipped_reason: "below_supported_floor"}]')
run_case "case8-below-floor-empty" 0 "$GAPS"

# ============================================================================
# Case 9: missing GH_REPO env → script hard-fails (no silent skip)
# ============================================================================
: > "$MOCK_LOG"
HIT=$(feat "x" 10)
jq -nc --argjson f "$HIT" '[{version: "2.1.999", features: [$f]}]' > "$WORK/shared/cc-adoption-gaps.json"
echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"
pushd "$WORK" >/dev/null
EXIT=0
env -u GH_REPO bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" \
  > /tmp/step3-norepo.out 2>&1 || EXIT=$?
popd >/dev/null
if [ "$EXIT" != "0" ] && grep -qF "GH_REPO is required" /tmp/step3-norepo.out; then
  log_pass "case 9: missing GH_REPO → exit non-zero with clear error"
else
  log_fail "case 9: missing GH_REPO" "exit=$EXIT, msg=$(cat /tmp/step3-norepo.out)"
fi

# ============================================================================
# Case 10: missing gh-issue-args.json → graceful skip (exit 0, no creates)
# ============================================================================
: > "$MOCK_LOG"
HIT=$(feat "x" 10)
jq -nc --argjson f "$HIT" '[{version: "2.1.999", features: [$f]}]' > "$WORK/shared/cc-adoption-gaps.json"
rm -f "$WORK/shared/gh-issue-args.json"
pushd "$WORK" >/dev/null
EXIT=0
GH_REPO="acme/orchestkit" bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" \
  > /tmp/step3-noargs.out 2>&1 || EXIT=$?
popd >/dev/null
CALLS=$(count_calls "issue|create")
if [ "$EXIT" = "0" ] && [ "$CALLS" = "0" ] && grep -qF "did not emit milestone" /tmp/step3-noargs.out; then
  log_pass "case 10: missing issue-args.json → 0 creates + graceful skip"
else
  log_fail "case 10" "exit=$EXIT, calls=$CALLS"
fi

# ============================================================================
# Case 11: stamp — after filing, every non-parse_failed entry gets
# `issues_filed_at` (so cc-release-watch prunes it from carry-forward next run,
# keeping the file bounded + never re-filing adopted/closed issues), while a
# parse_failed entry is left UNSTAMPED so it stays carried for --retry-failed.
# ============================================================================
: > "$MOCK_LOG"
HIT=$(feat "stamp-me" 15)
jq -nc --argjson f "$HIT" \
  '[{version: "2.1.997", features: [$f]}, {version: "2.1.996", parse_failed: true, features: []}]' \
  > "$WORK/shared/cc-adoption-gaps.json"
echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"
pushd "$WORK" >/dev/null
EXIT=0
MOCK_EXISTING_MILESTONE=1 GH_REPO="acme/orchestkit" \
  bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" > /tmp/step3-stamp.out 2>&1 || EXIT=$?
popd >/dev/null
STAMPED=$(jq -r '[.[] | select(.version=="2.1.997" and has("issues_filed_at"))] | length' "$WORK/shared/cc-adoption-gaps.json")
UNSTAMPED=$(jq -r '[.[] | select(.version=="2.1.996" and (has("issues_filed_at")|not))] | length' "$WORK/shared/cc-adoption-gaps.json")
if [ "$EXIT" = "0" ] && [ "$STAMPED" = "1" ] && [ "$UNSTAMPED" = "1" ]; then
  log_pass "case 11: filer stamps issues_filed_at on filed entry, leaves parse_failed unstamped"
else
  log_fail "case 11: stamp" "exit=$EXIT stamped=$STAMPED unstamped=$UNSTAMPED (see /tmp/step3-stamp.out)"
fi

# ============================================================================
# M169 — evidence-gated lanes (#2992 recall + #2993 precision)
# Cases below run with ORK_EVIDENCE_GATE=1 and a controlled EVIDENCE_ROOTS dir so
# the grep is hermetic (never touches the real plugin tree).
# ============================================================================

# Run the filer with the evidence gate ON against a specific evidence dir.
# Args: name gaps_json evidence_dir. Sets GATE_EXIT + leaves the rewritten ledger
# in $WORK/shared/cc-adoption-gaps.json for the caller to assert.
run_gate() {
  local name="$1" gaps_json="$2" evdir="$3"
  : > "$MOCK_LOG"
  echo "$gaps_json" > "$WORK/shared/cc-adoption-gaps.json"
  echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"
  pushd "$WORK" >/dev/null
  GATE_EXIT=0
  ORK_EVIDENCE_GATE=1 EVIDENCE_ROOTS="$evdir" \
  MOCK_EXISTING_MILESTONE=1 GH_REPO="acme/orchestkit" \
    bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" >"/tmp/step3-$name.out" 2>&1 \
    || GATE_EXIT=$?
  popd >/dev/null
}

# feature-slug disposition read helper
dispo_of() {
  jq -r --arg s "$1" \
    '[.[] | .features[]? | select(.feature_slug==$s) | .disposition] | .[0] // ""' \
    "$WORK/shared/cc-adoption-gaps.json"
}

# ---- Case 12 (#2993): above-floor + ZERO evidence → NOT filed, noop stamped ---
EVDIR=$(mktemp -d)   # empty dir = no evidence anywhere
F=$(feat "chrome_scroll_polish" 20)
GAPS=$(jq -nc --argjson f "$F" '[{version: "2.1.999", features: [$f]}]')
run_gate "case12-noop" "$GAPS" "$EVDIR"
CALLS=$(count_calls "issue|create")
D=$(dispo_of "chrome_scroll_polish")
if [ "$GATE_EXIT" = "0" ] && [ "$CALLS" = "0" ] && [ "$D" = "triaged-noop-no-evidence" ]; then
  log_pass "case 12: above-floor + no evidence → 0 creates, disposition=triaged-noop-no-evidence"
else
  log_fail "case 12" "exit=$GATE_EXIT calls=$CALLS dispo='$D' (see /tmp/step3-case12-noop.out)"
fi
rm -rf "$EVDIR"

# ---- Case 13 (#2992): sub-floor + evidence → filed via recall lane -----------
# The changelog line carries a mixedCase identifier (SessionStart) that appears
# in the evidence file — the STRONG-token hit that drives the recall lane.
EVDIR=$(mktemp -d)
echo "handles SessionStart source and fork materialization" > "$EVDIR/dispatcher.ts"
F=$(jq -nc '{feature_slug: "session_fork_source", gap_score: 5, description: "SessionStart reports source fork", category: "new_field", reference_changelog_line: "Changed SessionStart hooks to report source fork", affected_skills: []}')
GAPS=$(jq -nc --argjson f "$F" '[{version: "2.1.999", features: [$f]}]')
run_gate "case13-recall" "$GAPS" "$EVDIR"
CALLS=$(count_calls "issue|create")
D=$(dispo_of "session_fork_source")
CREATE_LINE=$(grep -F 'issue|create' "$MOCK_LOG" | head -1)
if [ "$GATE_EXIT" = "0" ] && [ "$CALLS" = "1" ] && [ -z "$D" ]; then
  log_pass "case 13: sub-floor + evidence → filed via recall lane (no disposition stamp)"
else
  log_fail "case 13" "exit=$GATE_EXIT calls=$CALLS dispo='$D' (see /tmp/step3-case13-recall.out)"
fi
if grep -qF "sub-floor score but codebase evidence" <<< "$CREATE_LINE"; then
  log_pass "case 13: recall-lane note present in issue body"
else
  log_fail "case 13: recall note" "body missing recall-lane marker"
fi
rm -rf "$EVDIR"

# ---- Case 14 (#2992): sub-floor + NO evidence → unfiled-subfloor -------------
EVDIR=$(mktemp -d)   # empty
F=$(feat "chrome_tab_group" 5)
GAPS=$(jq -nc --argjson f "$F" '[{version: "2.1.999", features: [$f]}]')
run_gate "case14-unfiled" "$GAPS" "$EVDIR"
CALLS=$(count_calls "issue|create")
D=$(dispo_of "chrome_tab_group")
if [ "$GATE_EXIT" = "0" ] && [ "$CALLS" = "0" ] && [ "$D" = "unfiled-subfloor" ]; then
  log_pass "case 14: sub-floor + no evidence → 0 creates, disposition=unfiled-subfloor"
else
  log_fail "case 14" "exit=$GATE_EXIT calls=$CALLS dispo='$D' (see /tmp/step3-case14-unfiled.out)"
fi
rm -rf "$EVDIR"

# ---- Case 15 (#2950 aid): cap-saturation stamp ------------------------------
# 20 features (== hard cap) → cap_saturated:true + a loud warning; a 3-feature
# version is left unstamped. Gate OFF so we do not file 20 issues; all features
# are sub-floor so the legacy precision path files nothing either.
: > "$MOCK_LOG"
BIG=$(jq -nc '[range(0;20) | {feature_slug: "cap\(.)", gap_score: 5, description: "d", category: "tooling", reference_changelog_line: "- x\(.)", affected_skills: []}]')
SMALL=$(jq -nc '[range(0;3) | {feature_slug: "small\(.)", gap_score: 5, description: "d", category: "tooling", reference_changelog_line: "- y\(.)", affected_skills: []}]')
jq -nc --argjson a "$BIG" --argjson b "$SMALL" \
  '[{version: "2.1.999", features: $a}, {version: "2.1.998", features: $b}]' \
  > "$WORK/shared/cc-adoption-gaps.json"
echo '{"milestone": "CC 2.1.999 adoption"}' > "$WORK/shared/gh-issue-args.json"
pushd "$WORK" >/dev/null
EXIT=0
ORK_EVIDENCE_GATE=0 MOCK_EXISTING_MILESTONE=1 GH_REPO="acme/orchestkit" \
  bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" > /tmp/step3-cap.out 2>&1 || EXIT=$?
popd >/dev/null
CAP_BIG=$(jq -r '.[] | select(.version=="2.1.999") | .cap_saturated // false' "$WORK/shared/cc-adoption-gaps.json")
CAP_SMALL=$(jq -r '.[] | select(.version=="2.1.998") | .cap_saturated // false' "$WORK/shared/cc-adoption-gaps.json")
if [ "$EXIT" = "0" ] && [ "$CAP_BIG" = "true" ] && [ "$CAP_SMALL" = "false" ] \
   && grep -qF "exactly 20 features" /tmp/step3-cap.out; then
  log_pass "case 15: cap-saturation stamps cap_saturated on the 20-feature version + warns"
else
  log_fail "case 15" "exit=$EXIT cap_big=$CAP_BIG cap_small=$CAP_SMALL (see /tmp/step3-cap.out)"
fi

# ---- Case 16 (#2993): above-floor WITH evidence → still files (gate-on happy) -
# The changelog line names a mixedCase identifier (SubagentStop) present in the
# evidence file — the STRONG-token hit that lets the precision lane file.
EVDIR=$(mktemp -d)
echo "the dispatcher handles the SubagentStop hook" > "$EVDIR/dispatcher.ts"
F=$(jq -nc '{feature_slug: "subagentstop_hook", gap_score: 15, description: "Added the SubagentStop hook", category: "new_event", reference_changelog_line: "Added the SubagentStop hook event", affected_skills: []}')
GAPS=$(jq -nc --argjson f "$F" '[{version: "2.1.999", features: [$f]}]')
run_gate "case16-gateon-file" "$GAPS" "$EVDIR"
CALLS=$(count_calls "issue|create")
D=$(dispo_of "subagentstop_hook")
if [ "$GATE_EXIT" = "0" ] && [ "$CALLS" = "1" ] && [ -z "$D" ]; then
  log_pass "case 16: above-floor + evidence (gate on) → filed, no disposition stamp"
else
  log_fail "case 16" "exit=$GATE_EXIT calls=$CALLS dispo='$D' (see /tmp/step3-case16-gateon-file.out)"
fi
rm -rf "$EVDIR"

# ============================================================================
# M169 real-tree ANCHOR cases — NON-hermetic. These run the evidence grep
# against the ACTUAL repo tree with the DEFAULT EVIDENCE_ROOTS (unset), from
# PROJECT_ROOT, so they assert the gate discriminates on real code. They define
# "working": if a tightening breaks either, the tightening is wrong.
# ============================================================================

# Run the filer from PROJECT_ROOT with the gate on and DEFAULT evidence roots,
# against a temp gaps/args file (never the real ledger). Leaves the rewritten
# ledger at $ANCHOR_GAPS for assertions.
run_anchor() {
  local name="$1" gaps_json="$2"
  : > "$MOCK_LOG"
  ANCHOR_GAPS="$WORK/anchor-gaps.json"
  echo "$gaps_json" > "$ANCHOR_GAPS"
  echo '{"milestone": "CC adoption"}' > "$WORK/anchor-args.json"
  pushd "$PROJECT_ROOT" >/dev/null
  ANCHOR_EXIT=0
  ORK_EVIDENCE_GATE=1 GAPS_FILE="$ANCHOR_GAPS" ISSUE_ARGS_FILE="$WORK/anchor-args.json" \
  MOCK_EXISTING_MILESTONE=1 GH_REPO="acme/orchestkit" \
    bash "$PROJECT_ROOT/scripts/cc-file-adoption-issues.sh" > "/tmp/step3-$name.out" 2>&1 \
    || ANCHOR_EXIT=$?
  popd >/dev/null
}

# ---- Anchor A (#2992): the REAL 2.1.214 sessionstart fork-source feature MUST
# evaluate hit — its surface is src/hooks/src/lifecycle/sync-session-dispatcher.ts.
REAL_REF='Changed SessionStart hooks to report source `"fork"` when a session begins as a fork instead of `"resume"`'
GAPS=$(jq -nc --arg ref "$REAL_REF" \
  '[{version: "2.1.214", features: [{feature_slug: "sessionstart_fork_source", gap_score: 5, description: "SessionStart hooks report source fork on a forked session", category: "new_field", reference_changelog_line: $ref, affected_skills: []}]}]')
run_anchor "anchorA-real-hit" "$GAPS"
CALLS=$(count_calls "issue|create")
if [ "$ANCHOR_EXIT" = "0" ] && [ "$CALLS" = "1" ]; then
  log_pass "anchor A: real sessionstart fork-source (score 5) → evidence hit → filed via recall lane"
else
  log_fail "anchor A" "exit=$ANCHOR_EXIT calls=$CALLS (see /tmp/step3-anchorA-real-hit.out)"
fi

# ---- Anchor B (#2993): a realistic end-user-only changelog line (full
# capitalized sentence, sentence-initial verb, no code identifier) MUST evaluate
# miss on the real tree.
GAPS=$(jq -nc \
  '[{version: "2.1.214", features: [{feature_slug: "chrome_scroll_polish", gap_score: 20, description: "Smoother scrollbar rendering and cursor polish in the transcript view", category: "breaking", reference_changelog_line: "Fixed scrollbar rendering and improved cursor polish in the transcript view", affected_skills: []}]}]')
run_anchor "anchorB-real-miss" "$GAPS"
CALLS=$(count_calls "issue|create")
D=$(jq -r '[.[] | .features[]? | select(.feature_slug=="chrome_scroll_polish") | .disposition] | .[0] // ""' "$ANCHOR_GAPS")
if [ "$ANCHOR_EXIT" = "0" ] && [ "$CALLS" = "0" ] && [ "$D" = "triaged-noop-no-evidence" ]; then
  log_pass "anchor B: end-user chrome_scroll_polish (score 20) → evidence miss → not filed on real tree"
else
  log_fail "anchor B" "exit=$ANCHOR_EXIT calls=$CALLS dispo='$D' (see /tmp/step3-anchorB-real-miss.out)"
fi

echo ""
echo "========================================================="
echo "  Results: $PASS passed, $FAIL failed"
echo "========================================================="

if [[ $FAIL -gt 0 ]]; then
  echo -e "${RED}FAIL${NC}"
  exit 1
fi
echo -e "${GREEN}SUCCESS${NC}"
